import{_ as e}from"./chunks/quick start autodetect motors.Bts2IrGD.js";import{_ as o,o as i,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Motors Setup Page","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/motors-setup-page.md","filePath":"robotics/motors-setup-page.md"}'),n={name:"robotics/motors-setup-page.md"};function s(l,t,u,c,h,d){return i(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="motors-setup-page" tabindex="-1">Motors Setup Page <a class="header-anchor" href="#motors-setup-page" aria-label="Permalink to &quot;Motors Setup Page&quot;">​</a></h1><p><strong>The direction that the motors will spin depends on how the vehicle and motors were assembled, so each motor&#39;s forward/reverse direction must be configured in software.</strong></p><p>To begin, navigate to the <strong>Motors</strong> tab in the sidebar on the left, then proceed with the <strong>automatic</strong> (recommended) or <strong>manual</strong> configuration.</p><blockquote><p>Be sure to keep all body parts and clothing clear of thrusters while the vehicle is armed.</p><p><strong>Warning</strong> <strong>DO NOT</strong> run thrusters for longer than 30 seconds in air or you will wear out the plastic bearings.</p></blockquote><h2 id="manual-motor-direction-setup" tabindex="-1">Manual Motor Direction Setup <a href="#manual-motor-direction-setup" id="manual-motor-direction-setup"></a> <a class="header-anchor" href="#manual-motor-direction-setup" aria-label="Permalink to &quot;Manual Motor Direction Setup &lt;a href=&quot;#manual-motor-direction-setup&quot; id=&quot;manual-motor-direction-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><ol><li>Go to the <strong>Motors</strong> tab in the sidebar on the left.</li><li>Read and understand the instructions on the setup page.</li><li>Arm the vehicle by clicking the switch on the page.</li><li>One at a time, move each slider, and make sure that the motor that spins is pushing air as described in the instructions on the Motor Setup page. If a motor is spinning in the wrong direction, click the corresponding checkbox under the &#39;Reverse Motor Direction&#39; section to correct the motor rotation.</li><li>When you are finished with the setup, disarm the vehicle by clicking the switch.</li></ol><h3 id="automatic-motor-direction-detection-setup" tabindex="-1">Automatic Motor Direction Detection Setup <a href="#automatic-motor-direction-detection-setup" id="automatic-motor-direction-detection-setup"></a> <a class="header-anchor" href="#automatic-motor-direction-detection-setup" aria-label="Permalink to &quot;Automatic Motor Direction Detection Setup &lt;a href=&quot;#automatic-motor-direction-detection-setup&quot; id=&quot;automatic-motor-direction-detection-setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ol><li>Adjust the vehicle&#39;s buoyancy to be neutral or slightly <strong>positive</strong>.</li><li>Place the vehicle in water with enough room for it to move around slightly without bumping into walls or the bottom. Make sure the vehicle has a bit of slack in the tether so that it can move freely.</li><li>Go to the <strong>Motors</strong> tab in the sidebar on the left.</li><li>Click the <strong>Auto-Detect Directions</strong> button, and wait while the vehicle does it&#39;s motor direction detection routine.</li><li>The results of the routine will appear as the routine progresses, and success or failure will be indicated. If the routine failed, you may try again, or configure the motor directions <strong>manually</strong>.</li></ol><p><img src="'+e+'" alt=""></p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',12)])])}const b=o(n,[["render",s]]);export{g as __pageData,b as default};
